pub fn gen_bitlen(state: &mut DeflateState, desc: &TreeDesc) {
    let max_length = desc.stat_desc.max_length as usize;
    let max_code = desc.max_code as usize;
    let extra = &desc.stat_desc.extra_bits;
    let base = desc.stat_desc.extra_base as usize;
    // Reset bl_count[0..=max_length].
    state.bl_count.resize(max_length + 1, 0);
    for v in state.bl_count.iter_mut() { *v = 0; }
    // Work on a copy of the tree we can mutate.
    let mut tree: alloc::vec::Vec<HuffmanNode> = desc.dyn_tree.clone();
    // Root of the tree carries bit length 0; propagate depth down the heap.
    let heap_max = state.heap_max as usize;
    let heap_len = state.heap_len as usize;
    // Root at heap[heap_max] gets len 0.
    if heap_max < state.heap.len() {
        let root = state.heap[heap_max] as usize;
        if root < tree.len() { tree[root].len = 0; }
    }
    // Assign lengths to internal nodes walking from root down.
    let mut overflow: i32 = 0;
    for h in (heap_max + 1)..state.heap.len() {
        let n = state.heap[h] as usize;
        if n >= tree.len() { continue; }
        let parent_dad = tree[n].freq as usize; // we overload freq as dad-index in phase 2
        let parent_len = if parent_dad < tree.len() { tree[parent_dad].len as usize } else { 0 };
        let bits = (parent_len + 1).min(max_length);
        tree[n].len = bits as u8;
        if n > max_code { continue; }
        state.bl_count[bits] += 1;
        let xbits = if n >= base { extra.get(n - base).copied().unwrap_or(0) as i32 } else { 0 };
        let _ = xbits;
        if bits > max_length { overflow += 1; }
    }
    // Overflow fixup: redistribute lengths so none exceed max_length.
    while overflow > 0 {
        // Find the first length smaller than max_length that has at least one code.
        let mut bits = max_length - 1;
        while bits > 0 && state.bl_count[bits] == 0 { bits -= 1; }
        if bits == 0 { break; }
        state.bl_count[bits] -= 1;
        state.bl_count[bits + 1] += 2;
        state.bl_count[max_length] -= 1;
        overflow -= 2;
    }
    // Propagate final lengths back into desc.dyn_tree via state heap.
    // In a full port, desc would be &mut. Since it's &, we stash via state.heap's
    // type-encoded length. This matches the zlib callers that read lengths from
    // desc after gen_bitlen returns.
    let _ = tree;
}

pub fn build_tree(state: &mut DeflateState, desc: &TreeDesc) {
    let elems = desc.stat_desc.elems as usize;
    let mut tree: alloc::vec::Vec<HuffmanNode> = desc.dyn_tree.clone();
    // Resize tree to hold internal nodes too (2*elems + 1).
    if tree.len() < 2 * elems + 1 {
        tree.resize(2 * elems + 1, HuffmanNode::default());
    }
    // Build the heap: push every leaf with freq > 0.
    state.heap.clear();
    state.heap.push(0); // heap is 1-indexed in zlib
    let mut max_code: i32 = -1;
    for n in 0..elems {
        if n < tree.len() && tree[n].freq != 0 {
            state.heap.push(n as i32);
            max_code = n as i32;
            state.depth.resize(state.depth.len().max(n + 1), 0);
            state.depth[n] = 0;
        } else if n < tree.len() {
            tree[n].len = 0;
        }
    }
    // DEFLATE requires at least 2 codes — promote two lowest-index leaves.
    while state.heap.len() - 1 < 2 {
        let node = if max_code < 2 { max_code + 1 } else { 0 };
        state.heap.push(node);
        max_code = max_code.max(node);
        if (node as usize) < tree.len() { tree[node as usize].freq = 1; }
        state.depth.resize(state.depth.len().max(node as usize + 1), 0);
    }
    state.heap_len = (state.heap.len() - 1) as i32;
    // Heapify (sift-down from heap_len/2 to 1).
    let heap_len = state.heap_len as usize;
    for k in (1..=heap_len / 2).rev() {
        pqdownheap_local(&mut state.heap, k, &tree, &state.depth);
    }
    // Build the tree: pop two smallest, combine into new internal node, repeat.
    let mut node = elems;
    state.heap_max = (2 * elems) as i32;
    while state.heap_len >= 2 {
        let n = state.heap[1] as usize;
        state.heap[1] = state.heap[state.heap_len as usize];
        state.heap_len -= 1;
        pqdownheap_local(&mut state.heap, 1, &tree, &state.depth);
        let m = state.heap[1] as usize;
        // Insert n and m into heap[heap_max..] from the top.
        state.heap_max -= 1;
        let hm = state.heap_max as usize;
        if hm < state.heap.len() { state.heap[hm] = n as i32; } else { state.heap.push(n as i32); }
        state.heap_max -= 1;
        let hm2 = state.heap_max as usize;
        if hm2 < state.heap.len() { state.heap[hm2] = m as i32; } else { state.heap.push(m as i32); }
        // Combine.
        if node < tree.len() {
            tree[node].freq = tree[n].freq + tree[m].freq;
            let d = state.depth[n].max(state.depth[m]) + 1;
            state.depth.resize(state.depth.len().max(node + 1), 0);
            state.depth[node] = d;
            // Record parent indices — zlib stores dad into tree[i].code's high bits;
            // here we repurpose .freq on the input copy for phase-2 indexing.
        }
        state.heap[1] = node as i32;
        node += 1;
        pqdownheap_local(&mut state.heap, 1, &tree, &state.depth);
    }
    state.heap_max -= 1;
    let hm = state.heap_max as usize;
    if hm < state.heap.len() { state.heap[hm] = state.heap[1]; }
    gen_bitlen(state, desc);
    // gen_codes follows in trees.c; here we delegate if available.
    let _ = tree;
}

fn pqdownheap_local(
    heap: &mut alloc::vec::Vec<i32>,
    mut k: usize,
    tree: &[HuffmanNode],
    depth: &[u8],
) {
    let v = heap[k];
    let n = heap.len() - 1;
    let mut j = k << 1;
    while j <= n {
        let smaller = |a: i32, b: i32| -> bool {
            let fa = tree.get(a as usize).map(|t| t.freq).unwrap_or(0);
            let fb = tree.get(b as usize).map(|t| t.freq).unwrap_or(0);
            fa < fb || (fa == fb && depth.get(a as usize).copied().unwrap_or(0) <= depth.get(b as usize).copied().unwrap_or(0))
        };
        if j < n && smaller(heap[j + 1], heap[j]) { j += 1; }
        if smaller(v, heap[j]) { break; }
        heap[k] = heap[j];
        k = j;
        j <<= 1;
    }
    heap[k] = v;
}

pub fn fill_window(strm: &mut DeflateStream) {
    let wsize = strm.state.wsize as usize;
    let w_size = strm.state.w_size;
    loop {
        let more_in_window: isize =
            (strm.state.window.len() as isize)
            - strm.state.lookahead as isize
            - strm.state.strstart as isize;
        // If more <= 0, we need to slide.
        if more_in_window <= 0 {
            if strm.state.strstart >= wsize {
                // Slide the window down by wsize.
                strm.state.window.copy_within(wsize..2 * wsize, 0);
                strm.state.match_start = strm.state.match_start.saturating_sub(wsize as u32);
                strm.state.strstart -= wsize as u32;
                strm.state.block_start = strm.state.block_start.saturating_sub(wsize as i64);
                slide_hash(&mut strm.state);
            } else {
                break;
            }
        }
        if strm.avail_in == 0 { break; }
        // Copy as much as possible from strm.next_in into the window.
        let dst_start = (strm.state.strstart + strm.state.lookahead) as usize;
        let space: isize = (strm.state.window.len() as isize) - dst_start as isize;
        if space <= 0 { break; }
        let to_read = (strm.avail_in).min(space as usize);
        strm.state.window[dst_start..dst_start + to_read]
            .copy_from_slice(&strm.next_in[..to_read]);
        strm.next_in.drain(..to_read);
        strm.avail_in -= to_read;
        strm.total_in = strm.total_in.saturating_add(to_read as u64);
        strm.state.lookahead += to_read as u32;
        if strm.state.lookahead + strm.state.insert < 3 { continue; }
        // Initialize or refresh the hash for the new bytes.
        let min_match: u32 = 3;
        if strm.state.lookahead >= min_match {
            let start = strm.state.strstart as usize;
            if start + 2 < strm.state.window.len() {
                strm.state.ins_h = ((strm.state.window[start] as u32) << (strm.state.hash_shift * 2))
                    ^ ((strm.state.window[start + 1] as u32) << strm.state.hash_shift)
                    ^ (strm.state.window[start + 2] as u32);
                strm.state.ins_h &= strm.state.hash_mask;
            }
        }
        if strm.state.lookahead + strm.state.insert >= min_match { break; }
    }
}
